from ariadne import QueryType, make_executable_schema, gql, graphql_sync
from flask import Flask, request, jsonify
from flask_cors import CORS

type_defs = gql("""
    type User {
        username: String!
        bio: String!
        email: String!
        phone: String!
        address: String!
    }

    type Query {
        userProfile: User
    }
""")

query = QueryType()

# Mock user data
mock_users = {
    "user1": {
        "username": "user1",
        "bio": "This is user1's bio.",
        "email": "user1@example.com",
        "phone": "123-456-7890",
        "address": "123 User St, User City, US"
    }
}

@query.field("userProfile")
def resolve_user_profile(_, info):
    current_user = info.context.get("current_user")
    if current_user and current_user in mock_users:
        return mock_users[current_user]
    return None

schema = make_executable_schema(type_defs, query)

app = Flask(__name__)
CORS(app)

@app.before_request
def authenticate():
    # Mock authentication
    token = request.headers.get("Authorization")
    if token == "Bearer valid_token":
        request.current_user = "user1"
    else:
        request.current_user = None

@app.route("/graphql", methods=["POST"])
def graphql_server():
    data = request.get_json()
    success, result = graphql_sync(
        schema,
        data,
        context_value=request,
        debug=app.debug,
    )
    status_code = 200 if success else 400
    return jsonify(result), status_code

if __name__ == "__main__":
    app.run(debug=True)